{
  "summary": "This paper proposes a method to create noisy parallel datasets for code translation by mining similar code samples across languages using document similarity metrics, particularly Word Movers Distance (WMD). The authors demonstrate that models trained on these noisy datasets maintain strong performance and robustness to noise, and extend supervised code translation to 10 programming languages beyond prior work.",
  "strengths": [
    {
      "point": "Novel approach to address scarcity of parallel code corpora by leveraging document similarity methods to create noisy parallel datasets.",
      "evidence": "The paper introduces a method that pairs code samples from different languages based on similarity scores, enabling supervised training without manually curated parallel data."
    },
    {
      "point": "Comprehensive empirical evaluation showing that code translation models tolerate moderate noise in training data with only gradual performance degradation.",
      "evidence": "Experiments with CodeBERT and GraphCodeBERT on datasets with varying noise levels demonstrate robustness, with only about 1 percentage point drop at ~90% match accuracy."
    },
    {
      "point": "Extension of code translation to a broader set of 10 programming languages and multiple language pairs beyond commonly studied ones.",
      "evidence": "The method is applied to CodeNet data for 10 languages, and PLBART models trained on WMD-matched datasets outperform random baselines across diverse pairs."
    },
    {
      "point": "Identification of Word Movers Distance (WMD) as an effective similarity metric for mining parallel code samples.",
      "evidence": "WMD consistently achieves the highest match accuracy (~90%) compared to other similarity methods like TF-IDF, Okapi-BM25, LDA, and LSI."
    },
    {
      "point": "Provision of reproducible experiments and partial dataset releases to facilitate further research.",
      "evidence": "The authors claim to provide partial datasets and code to support reproducibility."
    }
  ],
  "weaknesses": [
    {
      "point": "Lack of benchmarking against recent state-of-the-art unsupervised or weakly supervised code translation methods.",
      "evidence": "No comparisons to back-translation, adversarial training, or fine-tuned pretrained models like CodeT5 or PLBART are provided, limiting contextualization of novelty."
    },
    {
      "point": "No principled selection or sensitivity analysis of the similarity threshold (δ) used for pairing code samples.",
      "evidence": "The paper does not analyze how varying δ affects pairing precision, recall, or downstream translation performance, nor provide heuristics or adaptive strategies."
    },
    {
      "point": "Insufficient ablation and detailed analysis of components contributing to WMD's superior performance.",
      "evidence": "No exploration of tokenization granularity, embedding types, weighting schemes, or integration of structural code features like ASTs."
    },
    {
      "point": "Evaluation metrics focus on surface-level similarity without semantic correctness or runtime equivalence assessments.",
      "evidence": "Metrics like BLEU, CodeBLEU, Exact Match, and computational accuracy @5 do not guarantee semantic or functional equivalence; no execution-based evaluations are included."
    },
    {
      "point": "Absence of strong supervised baselines trained on large-scale clean parallel data or recent pretrained models fine-tuned on curated datasets.",
      "evidence": "Without such baselines, it is difficult to quantify the performance gap and practical utility of noisy data relative to best supervised approaches."
    },
    {
      "point": "Random pairing baseline is too weak; stronger heuristic baselines are needed for meaningful comparison.",
      "evidence": "Heuristics such as pairing by problem IDs or function signatures common in datasets like CodeNet are not considered."
    },
    {
      "point": "Insufficient details on code preprocessing and tokenization pipelines hinder reproducibility.",
      "evidence": "The paper lacks specification of tokenization schemes, normalization, or use of pretrained model tokenizers affecting similarity and model performance."
    },
    {
      "point": "Partial dataset release lacks clear scope, contents, and access information, limiting reproducibility.",
      "evidence": "No explicit details on which language pairs, code samples, or similarity scores are released, nor code availability."
    },
    {
      "point": "Ambiguous definition and quantification of noise in parallel datasets reduces clarity.",
      "evidence": "No formal metrics distinguishing syntactic similarity from semantic equivalence or partial correctness are provided."
    },
    {
      "point": "Lack of explanation on how Word Movers Distance is adapted or parameterized for source code.",
      "evidence": "No details on code-specific embeddings, handling of token order or syntax, or computational cost and scalability."
    },
    {
      "point": "No discussion of scalability and computational cost for large-scale codebases.",
      "evidence": "Pairwise similarity computations, especially with WMD, can be expensive; no runtime or optimization strategies are described."
    },
    {
      "point": "Ignoring structural and semantic code features in similarity computation is a significant limitation.",
      "evidence": "All similarity methods are token-based or latent semantic models without AST or control flow graph integration."
    },
    {
      "point": "Limited language diversity excludes functional, logic, and domain-specific languages, limiting generalizability.",
      "evidence": "Experiments focus on 10 imperative and object-oriented languages without discussion of applicability to other paradigms."
    },
    {
      "point": "Unknown performance on large or complex code units beyond snippets.",
      "evidence": "Experiments use small code snippets or competitive programming solutions; no evaluation on multi-file projects or complex dependencies."
    },
    {
      "point": "Lack of qualitative examples or visualizations of paired code samples and noise types reduces interpretability.",
      "evidence": "No side-by-side code pairs, similarity score distributions, or failure case analyses are provided."
    },
    {
      "point": "Impact of code style, formatting, and naming differences on similarity and translation quality is not addressed.",
      "evidence": "Such superficial differences can cause false positives/negatives in pairing and affect model performance."
    },
    {
      "point": "Effect of dataset domain and problem type on pairing effectiveness is overlooked.",
      "evidence": "No analysis of domain differences (e.g., algorithmic vs. real-world applications) on pairing quality or model generalization."
    },
    {
      "point": "Potential bias toward short or simple code snippets is not examined.",
      "evidence": "No analysis of code length or complexity distribution in paired datasets."
    },
    {
      "point": "Absence of detailed error analysis on translation failures limits insights for improvement.",
      "evidence": "No examination of specific language constructs or semantic errors causing failures."
    },
    {
      "point": "No discussion on handling code dependencies and context in translation.",
      "evidence": "Ignoring imports, external libraries, or modularity may limit translation quality for real-world codebases."
    }
  ],
  "questions": [
    {
      "question": "How does the proposed method compare quantitatively and qualitatively to recent unsupervised or weakly supervised code translation approaches?",
      "motivation": "Benchmarking against state-of-the-art methods is essential to contextualize novelty and practical advantages."
    },
    {
      "question": "What is the impact of varying the similarity threshold δ on pairing quality and downstream translation performance across different language pairs?",
      "motivation": "Understanding threshold sensitivity is critical for method robustness and generalizability."
    },
    {
      "question": "Can integrating structural code features (e.g., ASTs) into similarity computation reduce noise and improve pairing quality?",
      "motivation": "Token-based similarity may miss semantic equivalences; structural features could enhance dataset quality."
    },
    {
      "question": "How do models trained on noisy datasets perform on large-scale, real-world software projects with complex dependencies?",
      "motivation": "Evaluating on realistic codebases is necessary to assess practical applicability."
    },
    {
      "question": "What preprocessing and tokenization pipelines are used, and how do they affect similarity measures and model performance?",
      "motivation": "Reproducibility and understanding of method applicability depend on these details."
    }
  ],
  "scores": {
    "correctness": 3,
    "novelty": 3,
    "recommendation": "borderline",
    "confidence": 3
  }
}
